// lastError queries FFI error state and returns a Go error, or nil.
func (g *Game) lastError() error {
	code := ffi.LastErrorCode()
	if code == 0 {
		return nil
	}
	msg := ffi.LastErrorMessage()
	subsys := ffi.LastErrorSubsystem()
	op := ffi.LastErrorOperation()
	recovery := RecoveryClass(ffi.ErrorRecoveryClass(code))
	return &GoudError{
		Code:      code,
		Message:   msg,
		Category:  categoryFromCode(code),
		Subsystem: subsys,
		Operation: op,
		Recovery:  recovery,
	}
}
